import 'package:http/http.dart' as http;
import 'dart:convert';

void main() async {
  try {
    // Connect to cloud API using HTTPS
    var cloudResponse = await http.get(Uri.parse('https://api.example.com/data'), headers: {'Content-Type': 'application/json'});
    if (cloudResponse.statusCode == 200) {
      print('Cloud API Response: ${jsonDecode(cloudResponse.body)}');
    } else {
      throw Exception('Failed to load data from cloud API');
    }

    // Connect to local IoT device using HTTP
    var iotResponse = await http.get(Uri.parse('http://192.168.x.x/data'), headers: {'Content-Type': 'application/json'});
    if (iotResponse.statusCode == 200) {
      print('IoT Device Response: ${jsonDecode(iotResponse.body)}');
    } else {
      throw Exception('Failed to load data from IoT device');
    }
  } catch (e) {
    print('Error: $e');
  }
}